```class Solution {
public:
    vector<int> evenOddBit(int n) {
        vector<int> result;
        int countEven = 0;
        int countOdd = 0;

        while (n != 0) {
            n &= n - 1;
            countEven++;
            countOdd++;
        }

        result.push_back(countEven);
        result.push_back(countOdd);

        return result;
    }
};```

